/// Executor for DataExportRequest flow
pub struct DataExportRequestFlowExecutor<H: DataExportRequestStepHandler> {
    handler: Arc<H>,
}

impl<H: DataExportRequestStepHandler> DataExportRequestFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<DataExportRequestFlowInstance, FlowError> {
        let mut instance = DataExportRequestFlowInstance::new(instance_id);
        instance.status = DataExportRequestFlowStatus::Running;
        instance.current_step = Some(DataExportRequestFlowStep::FetchRequest);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut DataExportRequestFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            DataExportRequestFlowStep::FetchRequest => {
                self.handler.handle_fetch_request(instance).await?
            }
            DataExportRequestFlowStep::ValidateRequest => {
                self.handler.handle_validate_request(instance).await?
            }
            DataExportRequestFlowStep::CheckAuthorization => {
                let next = self.handler.evaluate_check_authorization(instance).await?;
                Some(next)
            }
            DataExportRequestFlowStep::LogUnauthorized => {
                self.handler.handle_log_unauthorized(instance).await?
            }
            DataExportRequestFlowStep::UpdateStatusProcessing => {
                self.handler.handle_update_status_processing(instance).await?
            }
            DataExportRequestFlowStep::CollectUserData => {
                self.handler.handle_collect_user_data(instance).await?
            }
            DataExportRequestFlowStep::LogCollectionError => {
                self.handler.handle_log_collection_error(instance).await?
            }
            DataExportRequestFlowStep::GenerateExport => {
                self.handler.handle_generate_export(instance).await?
            }
            DataExportRequestFlowStep::LogGenerationError => {
                self.handler.handle_log_generation_error(instance).await?
            }
            DataExportRequestFlowStep::CalculateExpiry => {
                self.handler.handle_calculate_expiry(instance).await?
            }
            DataExportRequestFlowStep::UpdateCompleted => {
                self.handler.handle_update_completed(instance).await?
            }
            DataExportRequestFlowStep::LogCompletion => {
                self.handler.handle_log_completion(instance).await?
            }
            DataExportRequestFlowStep::SendNotification => {
                self.handler.handle_send_notification(instance).await?
            }
            DataExportRequestFlowStep::MarkFailed => {
                self.handler.handle_mark_failed(instance).await?
            }
            DataExportRequestFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            DataExportRequestFlowStep::WorkflowFailed => {
                self.handler.handle_workflow_failed(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = DataExportRequestFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut DataExportRequestFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != DataExportRequestFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut DataExportRequestFlowInstance) {
        instance.status = DataExportRequestFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut DataExportRequestFlowInstance, error: impl Into<String>) {
        instance.status = DataExportRequestFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = DataExportRequestFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, DataExportRequestFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = DataExportRequestFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = DataExportRequestFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = DataExportRequestFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = DataExportRequestFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}